class FetchPosts extends PostEvent {}

import 'dart:convert';
import 'package:http/http.dart' as http;
import '../models/post.dart';

abstract class PostRepository {
  Future<List<Post>> getPosts();
}

class PostRepositoryImpl implements PostRepository {
  final http.Client client;

  PostRepositoryImpl({required this.client});

  @override
  Future<List<Post>> getPosts() async {
    final response = await client.get(
      Uri.parse('https://jsonplaceholder.typicode.com/posts'),
    );

    if (response.statusCode == 200) {
      final List<dynamic> jsonList = json.decode(response.body);
      return jsonList.map((json) => Post.fromJson(json)).toList();
    } else {
      throw Exception('Failed to load posts');
    }
  }
}

import 'package:flutter_bloc/flutter_bloc.dart';
import '../../models/post.dart';
import '../../repositories/post_repository.dart';
import 'post_event.dart';
import 'post_state.dart';

class PostBloc extends Bloc<PostEvent, PostState> {
  final PostRepository repository;

  PostBloc(this.repository) : super(PostInitial()) {
    on<FetchPosts>(_onFetchPosts);
  }

  Future<void> _onFetchPosts(FetchPosts event, Emitter<PostState> emit) async {
    emit(PostLoading());
    try {
      final posts = await repository.getPosts();
      emit(PostLoaded(posts));
    } catch (e) {
      emit(PostError(e.toString()));
    }
  }
}

import 'package:get_it/get_it.dart';
import 'package:http/http.dart' as http;
import '../features/posts/repositories/post_repository.dart';
import '../features/posts/bloc/post_bloc.dart';

final getIt = GetIt.instance;

void init() {
  getIt.registerLazySingleton<http.Client>(() => http.Client());
  getIt.registerLazySingleton<PostRepository>(
    () => PostRepositoryImpl(client: getIt()),
  );
  getIt.registerFactory(() => PostBloc(getIt<PostRepository>()));
}

import 'package:flutter/material.dart';
import 'package:flutter_bloc/flutter_bloc.dart';
import '../bloc/post_bloc.dart';
import '../bloc/post_event.dart';
import '../bloc/post_state.dart';

class PostPage extends StatelessWidget {
  @override
  Widget build(BuildContext context) {
    return BlocProvider(
      create: (_) => getIt<PostBloc>()..add(FetchPosts()),
      child: Scaffold(
        appBar: AppBar(title: Text('Posts')),
        body: BlocConsumer<PostBloc, PostState>(
          listener: (context, state) {
            if (state is PostError) {
              ScaffoldMessenger.of(context).showSnackBar(
                SnackBar(content: Text(state.message)),
              );
            }
          },
          builder: (context, state) {
            if (state is PostLoading) {
              return Center(child: CircularProgressIndicator());
            }
            if (state is PostLoaded) {
              return ListView.builder(
                itemCount: state.posts.length,
                itemBuilder: (_, index) {
                  final post = state.posts[index];
                  return ListTile(
                    title: Text(post.title),
                    subtitle: Text(post.body),
                  );
                },
              );
            }
            return Center(child: Text('Press button to load'));
          },
        ),
      ),
    );
  }
}

import 'package:dio/dio.dart';
import '../models/post.dart';

class PostRepositoryImpl implements PostRepository {
  final Dio dio;

  PostRepositoryImpl(this.dio);

  @override
  Future<List<Post>> getPosts() async {
    try {
      final response = await dio.get('/posts');
      final List<dynamic> jsonList = response.data;
      return jsonList.map((json) => Post.fromJson(json)).toList();
    } on DioException catch (e) {
      throw Exception('Network error: ${e.message}');
    }
  }
}

// In injection.dart
getIt.registerLazySingleton(() => Dio(BaseOptions(baseUrl: 'https://jsonplaceholder.typicode.com')));

// State
class PostLoaded extends PostState {
  final List<Post> posts;
  final bool hasReachedMax;
  const PostLoaded(this.posts, {this.hasReachedMax = false});

  PostLoaded copyWith({List<Post>? posts, bool? hasReachedMax}) {
    return PostLoaded(
      posts ?? this.posts,
      hasReachedMax: hasReachedMax ?? this.hasReachedMax,
    );
  }
}

// Event
class LoadMorePosts extends PostEvent {}

// In Bloc
on<LoadMorePosts>(_onLoadMore);

Future<void> _onLoadMore(LoadMorePosts event, Emitter<PostState> emit) async {
  final currentState = state;
  if (currentState is PostLoaded && !currentState.hasReachedMax) {
    final more = await repository.getPosts(page: currentState.posts.length ~/ 10 + 1);
    if (more.isEmpty) {
      emit(currentState.copyWith(hasReachedMax: true));
    } else {
      emit(PostLoaded(
        List.of(currentState.posts)..addAll(more),
      ));
    }
  }
}

